class Solution {
    public int numberOfArrays(String s, int k) {
        int n = s.length();
        long[] dp = new long[n + 1];
        dp[0] = 1;
        long mod = 1_000_000_007;
        for (int i = 1; i <= n; i++) {
            long cur = 0;
            for (int j = i - 1; j >= 0; j--) {
                if (s.charAt(j) == '0') break;
                int num = Integer.parseInt(s.substring(j, i));
                if (num <= k) cur = (cur + dp[j]) % mod;
            }
            dp[i] = cur;
        }
        return (int) dp[n];
    }
}
